INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'df193c90-5012-4b21-a2c2-e74e2f491da9',
  '00000000-0000-0000-0000-000000000001',
  $escape$esbuild Dev Server — Live Reload, Reverse Proxy, and HTTPS Without a Plugin$escape$,
  $escape$esbuild's built-in dev server, available via `context().serve()`, handles static file serving and incremental rebuilds out of the box — but true HMR isn't included. Instead, esbuild exposes a Server-Sent Events endpoint at `/__esbuild` that emits `change` events on every rebuild. Inject a small SSE listener into your entry point and call `location.reload()` to wire up live reload yourself.

For HTTPS, pass `certfile` and `keyfile` directly to `serve()`. Pair with `mkcert` to generate trusted local certs in seconds.

Proxy support isn't built-in, but `serve()` accepts an `onRequest` callback where you can forward unmatched requests (e.g., `/api/*`) to a backend using Node's `http.request`. This avoids CORS entirely during development. The `host` option lets you bind to `0.0.0.0` for LAN device testing. Combine `ctx.watch()` with `ctx.serve()` — watch triggers rebuilds, serve delivers the updated bundle. Never call `ctx.rebuild()` manually in dev; watch handles invalidation.$escape$,
  $escape$import * as esbuild from 'esbuild';
import * as http from 'node:http';

const ctx = await esbuild.context({ entryPoints: ['src/index.ts'], bundle: true, outdir: 'dist' });

await ctx.watch();

await ctx.serve({
  servedir: 'public',
  port: 3000,
  host: '0.0.0.0',
  certfile: 'certs/cert.pem',
  keyfile: 'certs/key.pem',
  onRequest({ method, path, remoteAddress, status, timeInMS }) {
    if (path.startsWith('/api/')) {
      // Forward to backend on :4000
      const proxy = http.request({ host: 'localhost', port: 4000, path, method });
      proxy.end();
    }
  },
});$escape$,
