INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '4f3ebfc7-7e87-4714-b03c-11b2d94aaa97',
  '00000000-0000-0000-0000-000000000001',
  $escape$esbuild CSS Processing — PostCSS, CSS Modules, and Preprocessor Support Explained$escape$,
  $escape$esbuild handles CSS natively but draws a hard line at PostCSS and preprocessors: it has no built-in support for either. For Sass/Less, you must pre-compile to plain CSS before passing files to esbuild — pipe `sass` output directly into esbuild's `stdin` using the `loader: { '.css': 'css' }` option, or run it as a separate step. CSS Modules are supported via `loader: { '.module.css': 'local-css' }` (added in v0.17). esbuild rewrites class names to unique identifiers and exposes them as a JS object via the default export. PostCSS requires an esbuild plugin — the `esbuild-postcss` or `esbuild-style-plugin` packages wrap PostCSS in an `onLoad` hook, intercept `.css` files, run the PostCSS pipeline, and return transformed CSS to esbuild. For autoprefixer or Tailwind v3 (which uses PostCSS internally), this plugin approach is mandatory. esbuild's own CSS bundler handles `@import` inlining and URL remapping natively — lean on that before reaching for plugins.$escape$,
  $escape$import esbuild from 'esbuild';
import postCSSPlugin from 'esbuild-postcss';
import autoprefixer from 'autoprefixer';

await esbuild.build({
  entryPoints: ['src/index.ts'],
  bundle: true,
  outdir: 'dist',
  plugins: [postCSSPlugin()],
  loader: {
    '.module.css': 'local-css',  // CSS Modules
    '.css': 'css',
  },
});$escape$,
  $escape$javascript$escape$,
