INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '60cb6787-b8e4-4742-9d6f-8f2e6b4feb59',
  '00000000-0000-0000-0000-000000000001',
  $escape$esbuild Aliasing & Path Resolution — Native alias vs. onResolve Plugins$escape$,
  $escape$esbuild's built-in `alias` option handles exact package-name substitution — ideal for swapping `react` with `preact/compat` or mocking heavy libs in tests. Pass it in `buildOptions` as a plain object: `alias: { 'react': 'preact/compat' }`. Resolution is exact-match only; it won't expand prefix patterns.

For TypeScript-style `@/` path aliases, `alias` falls short. esbuild has no native tsconfig `paths` resolver. Instead, write a small plugin using `build.onResolve`. Filter on a regex like `/^@\//`, strip the prefix, and return an absolute path via `path.resolve`. This runs at bundle time with zero runtime cost.

Two gotchas: First, `alias` entries take precedence over `node_modules` — use this intentionally to polyfill browser globals. Second, `onResolve` callbacks receive the importer's directory in `args.resolveDir`; use it when resolving relative-to-importer paths, not a hardcoded project root. Pair your plugin's resolved path with `namespace: 'file'` to keep esbuild's default file loader chain intact.$escape$,
  $escape$import * as esbuild from 'esbuild';
import path from 'path';

await esbuild.build({
  entryPoints: ['src/index.ts'],
  bundle: true,
  outdir: 'dist',
  alias: {
    'react': 'preact/compat',
    'react-dom/client': 'preact/compat',
  },
  plugins: [{
    name: 'at-alias',
    setup(build) {
      build.onResolve({ filter: /^\.?\@\// }, args => ({
        path: path.resolve('./src', args.path.replace(/^@\//, '')),
        namespace: 'file',
      }));
    },
  }],
});$escape$,
  $escape$javascript$escape$,
