INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'adf38236-e3db-4648-ac34-0978f30bf002',
  '00000000-0000-0000-0000-000000000001',
  $escape$esbuild in Vite — Pre-Bundling Deps in Dev While Rollup Takes Production$escape$,
  $escape$Vite uses esbuild for exactly two jobs in dev: transforming TypeScript/JSX (type-stripping only, no type-checking) and pre-bundling dependencies. Pre-bundling converts CJS/UMD packages to ESM and coalesces multi-file packages — lodash-es ships 600+ files — into a single cached module at node_modules/.vite/deps. Without this, the browser would fire hundreds of cascading HTTP requests before your page renders a single component.

The cache is keyed to your lockfile hash and reruns only on dep changes. Force a rebuild with `vite --force` or by deleting node_modules/.vite manually.

In production, Vite swaps esbuild for Rollup, which has more mature support for advanced code splitting, deterministic chunk hashing, and tree-shaking across dynamic imports. But esbuild stays available as the prod minifier via `build.minify: 'esbuild'` — 20–40x faster than Terser with negligible output size difference.

Customize pre-bundling through `optimizeDeps.esbuildOptions`, which accepts the full esbuild build API surface: loaders, define substitutions, and esbuild plugins. The `esbuild` top-level key separately controls the transform step for your source files.$escape$,
  $escape$// vite.config.ts
import { defineConfig } from 'vite'

export default defineConfig({
  optimizeDeps: {
    include: ['lodash-es', 'some-cjs-pkg'],
    esbuildOptions: {
      define: { global: 'globalThis' },
      loader: { '.node': 'file' },
    },
  },
  esbuild: {
    target: 'es2020',
    jsxInject: `import React from 'react'`,
  },
  build: {
    minify: 'esbuild',
  },
})$escape$,
  $escape$typescript$escape$,
